import 'package:injectable/injectable.dart'; import 'package:shared_preferences/shared_preferences.dart'; import '../../core/utils/app_logger.dart'; @injectable class RateAppService { static const _key = 'rate_app_shown'; Future<bool> shouldPrompt() async { final prefs = await SharedPreferences.getInstance(); if (prefs.getBool(_key) == true) return false; final count = prefs.getInt('session_count') ?? 0; return count >= 5; } Future<void> markShown() async { final prefs = await SharedPreferences.getInstance(); await prefs.setBool(_key, true); } Future<void> openPlayStore() async { AppLogger.info('Opening Play Store for rating'); } }